package format

import (
	"strings"
	"testing"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
)

func TestCompactDiffFormatter_Empty(t *testing.T) {
	formatter := &CompactDiffFormatter{}
	plan := &plans.Plan{
		Changes: plans.NewChangesSrc(),
	}

	result := formatter.Format(plan, nil)
	if result != "" {
		t.Errorf("Expected empty string for empty plan, got: %q", result)
	}
}

func TestCompactDiffFormatter_SingleCreate(t *testing.T) {
	formatter := &CompactDiffFormatter{}

	// Create a simple plan with one resource creation
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "example",
							},
						},
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
				},
			},
		},
	}

	result := formatter.Format(plan, nil)

	// Check that output contains expected elements
	if !strings.Contains(result, "Create (1)") {
		t.Errorf("Expected 'Create (1)' in output, got: %q", result)
	}
	if !strings.Contains(result, "[+] aws_instance.example") {
		t.Errorf("Expected '[+] aws_instance.example' in output, got: %q", result)
	}
	if !strings.Contains(result, "Plan: 1 resource changes") {
		t.Errorf("Expected 'Plan: 1 resource changes' in output, got: %q", result)
	}
}

func TestCompactDiffFormatter_MultipleActions(t *testing.T) {
	formatter := &CompactDiffFormatter{}

	// Create a plan with multiple resource changes
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "web",
							},
						},
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
				},
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_security_group",
								Name: "default",
							},
						},
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Delete,
					},
				},
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "db",
							},
						},
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Update,
					},
				},
			},
		},
	}

	result := formatter.Format(plan, nil)

	// Check for all action groups
	if !strings.Contains(result, "Create (1)") {
		t.Errorf("Expected 'Create (1)' in output")
	}
	if !strings.Contains(result, "Update (1)") {
		t.Errorf("Expected 'Update (1)' in output")
	}
	if !strings.Contains(result, "Delete (1)") {
		t.Errorf("Expected 'Delete (1)' in output")
	}

	// Check for specific resources
	if !strings.Contains(result, "[+] aws_instance.web") {
		t.Errorf("Expected '[+] aws_instance.web' in output")
	}
	if !strings.Contains(result, "[-] aws_security_group.default") {
		t.Errorf("Expected '[-] aws_security_group.default' in output")
	}
	if !strings.Contains(result, "[~] aws_instance.db") {
		t.Errorf("Expected '[~] aws_instance.db' in output")
	}

	// Check summary
	if !strings.Contains(result, "Plan: 3 resource changes") {
		t.Errorf("Expected 'Plan: 3 resource changes' in output")
	}
}

func TestCompactDiffFormatter_SortsWithinAction(t *testing.T) {
	formatter := &CompactDiffFormatter{}

	// Create a plan with multiple creates in different order
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "zebra",
							},
						},
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
				},
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "alpha",
							},
						},
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
				},
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_s3_bucket",
								Name: "beta",
							},
						},
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
				},
			},
		},
	}

	result := formatter.Format(plan, nil)

	// Find the positions of each resource in the output
	posAlpha := strings.Index(result, "aws_instance.alpha")
	posBeta := strings.Index(result, "aws_s3_bucket.beta")
	posZebra := strings.Index(result, "aws_instance.zebra")

	if posAlpha < 0 || posBeta < 0 || posZebra < 0 {
		t.Fatalf("Not all resources found in output")
	}

	// Verify they are sorted
	if posAlpha > posBeta || posBeta > posZebra {
		t.Errorf("Resources not sorted correctly. Got positions: alpha=%d, beta=%d, zebra=%d", posAlpha, posBeta, posZebra)
	}
}

func TestCompactDiffFormatter_IgnoresNoOp(t *testing.T) {
	formatter := &CompactDiffFormatter{}

	// Create a plan with mix of no-ops and real changes
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "noop1",
							},
						},
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.NoOp,
					},
				},
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "create1",
							},
						},
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
				},
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "noop2",
							},
						},
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.NoOp,
					},
				},
			},
		},
	}

	result := formatter.Format(plan, nil)

	// Check that no-ops are not in the output
	if strings.Contains(result, "noop1") || strings.Contains(result, "noop2") {
		t.Errorf("No-op resources should not appear in output")
	}

	// Check that the create is in the output
	if !strings.Contains(result, "create1") {
		t.Errorf("Create resource should appear in output")
	}

	// Check that the count is correct
	if !strings.Contains(result, "Plan: 1 resource changes") {
		t.Errorf("Should report 1 resource change, not 3")
	}
}

func TestCompactDiffFormatter_NilPlan(t *testing.T) {
	formatter := &CompactDiffFormatter{}

	result := formatter.Format(nil, nil)
	if result != "" {
		t.Errorf("Expected empty string for nil plan, got: %q", result)
	}
}

func TestCompactDiffFormatter_ReplaceActions(t *testing.T) {
	formatter := &CompactDiffFormatter{}

	// Create a plan with replace actions
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "replace1",
							},
						},
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.DeleteThenCreate,
					},
				},
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "replace2",
							},
						},
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.CreateThenDelete,
					},
				},
			},
		},
	}

	result := formatter.Format(plan, nil)

	// Check for replace actions
	if !strings.Contains(result, "Replace (delete then create)") {
		t.Errorf("Expected replace (delete then create) header in output")
	}
	if !strings.Contains(result, "Replace (create then delete)") {
		t.Errorf("Expected replace (create then delete) header in output")
	}

	// Check for specific symbols
	if !strings.Contains(result, "[∓]") {
		t.Errorf("Expected '[∓]' symbol in output")
	}
	if !strings.Contains(result, "[±]") {
		t.Errorf("Expected '[±]' symbol in output")
	}
}

